const item = $input.first().json || {};
const textRaw = item.conversation?.last_message || item.texto || "";
const text = String(textRaw).trim();
const lower = text.toLowerCase();

// =========================
// HELPERS
// =========================
function clean(value) {
  if (!value) return null;

  const t = String(value).trim();
  const l = t.toLowerCase();

  const invalid = [
    "não informado",
    "nao informado",
    "não informada",
    "nao informada",
    "sem histórico",
    "sem historico",
    "[null]",
    "null"
  ];

  if (invalid.includes(l)) return null;

  return t;
}

function cap(str) {
  if (!str) return null;
  return str
    .split(" ")
    .filter(Boolean)
    .map(s => s.charAt(0).toUpperCase() + s.slice(1).toLowerCase())
    .join(" ");
}

function cleanCep(value) {
  if (!value) return null;
  const digits = String(value).replace(/\D/g, "");
  return digits || null;
}

// =========================
// CAMPOS EXTRAÍDOS
// =========================
let nome = null;
let produto = null;
let cidade = null;
let cep = null;
let endereco = null;

// =========================
// NOME
// =========================
let m =
  text.match(/\bmeu nome é ([A-Za-zÀ-ÿ]+(?:\s+[A-Za-zÀ-ÿ]+){0,2})/i) ||
  text.match(/\beu sou ([A-Za-zÀ-ÿ]+(?:\s+[A-Za-zÀ-ÿ]+){0,2})/i) ||
  text.match(/\bsou ([A-Za-zÀ-ÿ]+(?:\s+[A-Za-zÀ-ÿ]+){0,2})/i) ||
  text.match(/^(oi|olá|ola|bom dia|boa tarde|boa noite)\s+([A-Za-zÀ-ÿ]+)/i);

if (m) {
  nome = cap(m[2] || m[1]);
}

// =========================
// PRODUTO (ROUPAS)
// =========================
const produtosRoupas = [
  "blusa",
  "camiseta",
  "vestido",
  "conjunto",
  "tricot",
  "casaco",
  "jaqueta",
  "calça",
  "short",
  "saia",
  "roupa",
  "moda"
];

for (const p of produtosRoupas) {
  if (lower.includes(p)) {
    produto = cap(p);
    break;
  }
}

// =========================
// CIDADE (EVITA PEGAR FRASES COMO "qual a localização")
// =========================
m =
  text.match(/\bsou de ([A-Za-zÀ-ÿ\s\-]{2,40})$/i) ||
  text.match(/\bmoro em ([A-Za-zÀ-ÿ\s\-]{2,40})$/i) ||
  text.match(/\bestou em ([A-Za-zÀ-ÿ\s\-]{2,40})$/i);

if (m) {
  cidade = cap(m[1].trim());
}

// =========================
// CEP
// =========================
m = text.match(/\b\d{5}-?\d{3}\b/);
if (m) {
  cep = cleanCep(m[0]);
}

// =========================
// ENDEREÇO
// =========================
m = text.match(
  /\b(rua|r\.|avenida|av\.|travessa|trav\.|alameda)\s+[A-Za-zÀ-ÿ0-9\s,\-]{3,80}/i
);

if (m) {
  endereco = cap(m[0].trim());
}

// =========================
// CONTEXTO LIMPO PARA SDR
// =========================
return [
  {
    json: {
      contexto_kb: item.contexto_kb || "",

      lead_context: {
        name: clean(item.lead_context?.name),
        id: item.lead_context?.id || null,
        ref: item.lead_context?.ref || null,
        product_interest: clean(item.lead_context?.product_interest),
        current_stage: clean(item.lead_context?.current_stage) || "novo",
        channel: clean(item.lead_context?.channel),
        city: clean(item.lead_context?.city),
        cep: cleanCep(item.lead_context?.cep)
      },

      conversation: {
        last_message: text,
        history: clean(item.conversation?.history)
      },

      detected_fields: {
        nome,
        produto,
        cidade,
        cep,
        endereco
      }
    }
  }
];

