const docs = $input.all();

const seen = new Set();
const chunks = [];

for (const item of docs) {
  const original = item.json.document?.pageContent?.trim();
  if (!original) continue;

  const normalized = original
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();

  if (seen.has(normalized)) continue;

  seen.add(normalized);
  chunks.push(original);
}

return [
  {
    json: {
      contexto_kb: chunks.join('\n\n')
    }
  }
];

let raw = $json.output;

// 1. Se vier como string, parseia
if (typeof raw === 'string') {
  try {
    raw = JSON.parse(raw);
  } catch (e) {
    return [{
      json: {
        error: 'INVALID_JSON',
        raw_output: $json.output
      }
    }];
  }
}

// 2. Normaliza estrutura
return [{
  json: {
    reply: raw.reply || null,
    name: raw.detected_fields?.nome || null,
    produto: raw.detected_fields?.produto || null,
    cidade: raw.detected_fields?.cidade || null,
    cep: raw.detected_fields?.cep || null,
    endereco: raw.detected_fields?.endereco || null,
  }
}];

// ==========================
// COMPUTE SCORE & TAGS
// ==========================

const classifierNode = $input.first().json || {};
const mapped = $items("Map Input Classifier", 0, 0)?.[0]?.json || {};
const unified = $items("Unify Lead Data", 0, 0)?.[0]?.json || {};

// ==========================
// NORMALIZAÇÃO DA SAÍDA DO CLASSIFIER
// Suporta:
// 1) saída estruturada direta
// 2) { output: "{...json...}" }
// 3) { output: {...} }
// ==========================

let parsed = {};

try {
  if (
    classifierNode &&
    typeof classifierNode === "object" &&
    "intent" in classifierNode
  ) {
    parsed = classifierNode;
  } else if (typeof classifierNode.output === "string") {
    parsed = JSON.parse(classifierNode.output);
  } else if (
    classifierNode.output &&
    typeof classifierNode.output === "object"
  ) {
    parsed = classifierNode.output;
  } else {
    parsed = {};
  }
} catch (error) {
  parsed = {};
}

// ==========================
// BASE CONSOLIDADA
// prioridade:
// classifier > mapped > unified
// ==========================

const base = {
  ...unified,
  ...mapped,
  ...parsed
};

// ==========================
// HELPERS
// ==========================

function normalizeText(value) {
  return (value ?? "").toString().trim();
}

function normalizeLower(value) {
  return normalizeText(value).toLowerCase();
}

function addTag(tag, tags) {
  if (tag && !tags.includes(tag)) tags.push(tag);
}

// ==========================
// CAMPOS PRINCIPAIS
// ==========================

const intent = normalizeText(base.intent);
const interest = normalizeLower(base.interest_level);
const urgency = normalizeLower(base.urgency);
const fit = normalizeLower(base.fit);
const summary = normalizeText(base.summary);
const objections = Array.isArray(base.objections) ? base.objections : [];

// lead data
const leadRef = base.lead_ref ?? base.ref ?? null;
const leadId = base.lead_id ?? base.id ?? null;
const leadName = normalizeText(base.lead_name || base.name || base.nome) || null;
const leadStage = normalizeText(base.lead_stage || base.stage || base.current_stage) || "novo";
const aiEnabled = base.ai_enabled ?? true;
const productInterest = normalizeText(
  base.product_interest || base.productInterest || base.interesse_produto
) || null;
const city = normalizeText(base.city || base.cidade) || null;
const cep = normalizeText(base.cep) || null;
const channel = normalizeText(base.channel || base.canal) || null;

// message data
const messageText = normalizeText(
  base.last_message ||
  base.mensagem ||
  base.ultima_mensagem ||
  base.message ||
  base.text
);

const classifierInput = normalizeText(base.classifier_input);

// ==========================
// SCORE + TAGS
// ==========================

let score = 0;
const tags = [];

// --------------------------
// INTENT
// --------------------------

switch (intent) {
  case "quer_preco_frete":
    score += 30;
    addTag("frete", tags);
    addTag("intencao_compra", tags);
    break;

  case "quer_preco_produto":
    score += 25;
    addTag("preco_produto", tags);
    addTag("intencao_compra", tags);
    break;

  case "quer_condicao_pagamento":
    score += 30;
    addTag("condicao_pagamento", tags);
    addTag("negociacao", tags);
    break;

  case "quer_comprar":
    score += 40;
    addTag("compra_direta", tags);
    addTag("intencao_compra", tags);
    addTag("lead_quente", tags);
    break;

  case "interesse_produto":
    score += 15;
    addTag("interesse_produto", tags);
    break;

  case "comparando_opcoes":
    score += 10;
    addTag("comparando_opcoes", tags);
    break;

  case "duvida_geral":
    score += 5;
    addTag("duvida_geral", tags);
    break;

  case "follow_up":
    score += 5;
    addTag("follow_up", tags);
    break;

  case "suporte":
    addTag("suporte", tags);
    break;

  case "especificacao_produto":
    score += 10;
    addTag("especificacao_produto", tags);
    break;

  case "sem_intencao_clara":
    addTag("sem_intencao_clara", tags);
    break;
}

// --------------------------
// INTEREST
// --------------------------

if (interest === "alto") {
  score += 20;
  addTag("lead_quente", tags);
} else if (interest === "medio") {
  score += 10;
  addTag("lead_morno", tags);
} else if (interest === "baixo") {
  addTag("lead_frio", tags);
}

// --------------------------
// URGENCY
// --------------------------

if (urgency === "alta") {
  score += 20;
  addTag("urgencia_alta", tags);
} else if (urgency === "media") {
  score += 10;
  addTag("urgencia_media", tags);
} else if (urgency === "baixa") {
  addTag("urgencia_baixa", tags);
}

// --------------------------
// FIT
// --------------------------

if (fit === "bom") {
  score += 15;
  addTag("fit_bom", tags);
} else if (fit === "neutro") {
  score += 5;
  addTag("fit_neutro", tags);
} else if (fit === "ruim") {
  addTag("fit_ruim", tags);
}

// --------------------------
// DADOS ÚTEIS DO LEAD
// --------------------------

if (productInterest) addTag("produto_identificado", tags);
if (city) addTag("cidade_detectada", tags);
if (cep) {
  addTag("cep_detectado", tags);
  score += 10;
}

// CEP vindo da mensagem
if (!cep && /\b\d{8}\b/.test(messageText)) {
  addTag("cep_detectado", tags);
  score += 10;
}

// --------------------------
// OBJECTIONS
// --------------------------

for (const obj of objections) {
  addTag(obj, tags);

  if (obj === "objecao_preco") score -= 10;
  if (obj === "objecao_tempo") score -= 5;
  if (obj === "objecao_confianca") score -= 15;
  if (obj === "comparando_concorrente") score -= 5;
  if (obj === "sem_resposta") score -= 10;
}

// --------------------------
// LIMITADOR
// --------------------------

score = Math.max(0, Math.min(score, 100));

// ==========================
// FUNNEL STAGE
// ==========================

let funnel_stage = "novo";
if (score > 20) funnel_stage = "contatado";
if (score > 40) funnel_stage = "engajado";
if (score > 60) funnel_stage = "qualificado";
if (score > 80) funnel_stage = "oportunidade";

// ==========================
// ROUTE HINT
// prioridade do classifier
// upgrade controlado apenas se fizer sentido
// ==========================

let route_hint = normalizeText(base.route_hint) || "SDR";

if (
  route_hint === "SDR" &&
  score > 80 &&
  productInterest &&
  (
    intent === "quer_comprar" ||
    intent === "quer_preco_produto" ||
    intent === "quer_condicao_pagamento" ||
    intent === "quer_preco_frete"
  )
) {
  route_hint = "CLOSER";
}

// ==========================
// OUTPUT
// ==========================

return [
  {
    json: {
      lead: {
        ref: leadRef,
        id: leadId,
        name: leadName,
        stage: leadStage,
        ai_enabled: aiEnabled,
        product_interest: productInterest,
        city,
        cep,
        channel
      },
      message: {
        text: messageText,
        classifier_input: classifierInput
      },
      classifier: {
        intent,
        interest_level: interest || null,
        urgency: urgency || null,
        fit: fit || null,
        objections,
        summary,
        route_hint
      },
      crm: {
        score,
        tags,
        funnel_stage
      }
    }
  }
];

const item = $input.first().json;

const score = item.crm_context?.score || 0;
const intent = item.classification?.intent || "";
const routeHint = item.classification?.route_hint || "SDR";
const stage = item.stage_decision?.new_funnel_stage || "novo";

let action = "send_to_sdr";
let priority = "medium";
let handoffTo = "SDR";
let shouldUpdateStage = true;
let reason = "Default";

// prioridade
if (score >= 80) priority = "high";
if (score < 40) priority = "low";

// decisão principal
if (intent === "quer_comprar") {
  action = "send_to_closer";
  handoffTo = "Closer";
  priority = "high";
  reason = "Intenção direta de compra";
}

else if (intent === "quer_condicao_pagamento") {
  action = "send_to_closer";
  handoffTo = "Closer";
  reason = "Negociação";
}

else if (intent === "suporte") {
  action = "send_to_support";
  handoffTo = "Support";
  shouldUpdateStage = false;
  reason = "Solicitação de suporte";
}

else if (score < 30) {
  action = "follow_up";
  handoffTo = "SDR";
  reason = "Lead frio";
}

return [
  {
    json: {
      ...item,
      funnel_decision: {
        action,
        priority,
        handoff_to: handoffTo,
        should_update_stage: shouldUpdateStage,
        target_stage: stage,
        reason
      }
    }
  }
];

const text = ($json.text || "").toString().trim();

const hasText = text.length > 0;
const hasMedia = !!$json.has_media;

if (!hasText && !hasMedia) {
  return [];
}

return [
  {
    json: {
      ...$json,
      text
    }
  }
];

// =========================
// HELPERS
// =========================
function asNull(value) {
  return value === undefined || value === null || value === '' ? null : value;
}

function safeBool(value) {
  return value === true;
}

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return null;
}

// =========================
// INPUTS CORRETOS (FIXO)
// =========================

// 🔥 AGORA SIM — BUSCA PELO NODE CERTO
const closerNode = $('Agente Closer').first()?.json || {};
const contexto = $('Preparar Contexto Closer').first()?.json || {};

// =========================
// PARSE DO OUTPUT DO CLOSER
// =========================
let raw = closerNode.output ?? closerNode;

// array (n8n)
if (Array.isArray(raw)) {
  raw = raw[0]?.text || raw[0] || null;
}

// string
if (typeof raw === 'string') {
  try {
    raw = JSON.parse(raw);
  } catch {
    raw = {
      reply: raw,
      produto: null,
      link: null,
      oferta_pix: false,
      handoff_humano: false,
      motivo_handoff: null
    };
  }
}

// wrapper
if (raw && raw.output) {
  raw = raw.output;
}

// fallback final
if (!raw || typeof raw !== 'object') {
  raw = {
    reply: null,
    produto: null,
    link: null,
    oferta_pix: false,
    handoff_humano: false,
    motivo_handoff: null
  };
}

// =========================
// CAMPOS CORRETOS
// =========================

const lead_ref = asNull(contexto.lead_ref);
const lead_id = asNull(contexto.lead_id);

const name = asNull(pick(contexto.nome, contexto.name));
const canal = asNull(pick(contexto.canal, contexto.channel));
const stage = asNull(pick(contexto.stage, contexto.current_stage));

const produto_contexto = asNull(
  pick(contexto.product_interest, contexto.produto)
);

// 🔥 CONSOLIDAÇÃO
const produto =  produto_contexto || null;

const city = asNull(pick(contexto.city, contexto.cidade));
const cep = asNull(contexto.cep);

const contexto_closer = asNull(contexto.contexto_closer);

// 🔥 ESSA LINHA ERA UM DOS ERROS
const originalMessage = asNull(
  pick(contexto.texto, contexto.message)
);

// =========================
// OUTPUT FINAL
// =========================
return [
  {
    json: {
      error: null,

      lead_ref,
      lead_id,
      name,
      canal,
      stage,

      produto,

      city,
      cep,

      contexto_closer,

      message: originalMessage,
      reply: asNull(raw.reply),

      link: asNull(raw.link),
      oferta_pix: safeBool(raw.oferta_pix),

      handoff_humano: safeBool(raw.handoff_humano),
      motivo_handoff: asNull(raw.motivo_handoff)
    }
  }
];

