const contact = $json.contacts?.[0] || {};

const type = msg.type || "unknown";
const text =
  msg.text?.body ||
  msg.caption ||
  "";

let media_id = null;
let filename = null;
let mime = null;
let direct_url = null;
let has_media = false;
let media_kind = null;

if (msg.image) {
  has_media = true;
  media_kind = "image";
  media_id = msg.image.id || null;
  mime = msg.image.mime_type || "image";
  direct_url = msg.image.url || null;
}

if (msg.document) {
  has_media = true;
  media_kind = "document";
  media_id = msg.document.id || null;
  filename = msg.document.filename || null;
  mime = msg.document.mime_type || null;
  direct_url = msg.document.url || null;
}

const is_heic =
  (filename || "").toLowerCase().endsWith(".heic") ||
  (mime || "").toLowerCase().includes("heic");

return [{
  json: {
    lead_id: contact.wa_id || msg.from || null,
    nome: contact.profile?.name || "",
    msg_id: msg.id || null,
    timestamp: msg.timestamp || null,

    // base comum
    message_type: type,
    text,
    has_text: !!text,
    has_media,
    media_kind,
    media_id,
    filename,
    mime,
    direct_url,
    is_heic,

    // flags de roteamento
    route_text: !!text,
    route_media: has_media
  }
}];

const item = $input.first().json || {};

// =========================
// HELPERS
// =========================
function firstDefined(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== "") {
      return value;
    }
  }
  return null;
}

function normalizeText(value) {
  if (value === undefined || value === null) return null;

  const text = String(value).trim();
  if (!text) return null;

  const lower = text.toLowerCase();

  const invalidValues = [
    "não informado",
    "nao informado",
    "não informada",
    "nao informada",
    "não informado anteriormente",
    "nao informado anteriormente",
    "não informada anteriormente",
    "nao informada anteriormente",
    "null",
    "[null]",
    "undefined",
    "sem histórico",
    "sem historico"
  ];

  if (invalidValues.includes(lower)) return null;

  return text;
}

function normalizeCep(value) {
  const text = normalizeText(value);
  if (!text) return null;

  const digits = text.replace(/\D/g, "");
  return digits || null;
}

// =========================
// LEAD CONTEXT LIMPO
// =========================
const leadContext = {
  name: normalizeText(
    firstDefined(
      item.lead_context?.name,
      item.lead?.name,
      item.nome,
      item.name
    )
  ),

  id: firstDefined(
    item.lead_context?.id,
    item.lead?.id,
    item.id,
    item.lead_id
  ),

  ref: firstDefined(
    item.lead_context?.ref,
    item.lead?.ref,
    item.ref,
    item.lead_ref
  ),

  product_interest: normalizeText(
    firstDefined(
      item.lead_context?.product_interest,
      item.lead_context?.productInterest,
      item.lead?.product_interest,
      item.product_interest,
      item.interesse_produto
    )
  ),

  current_stage: normalizeText(
    firstDefined(
      item.lead_context?.current_stage,
      item.lead?.stage,
      item.current_stage,
      item.stage
    )
  ) || "novo",

  channel: normalizeText(
    firstDefined(
      item.lead_context?.channel,
      item.lead?.channel,
      item.channel,
      item.canal
    )
  ),

  city: normalizeText(
    firstDefined(
      item.lead_context?.city,
      item.lead?.city,
      item.city,
      item.cidade
    )
  ),

  cep: normalizeCep(
    firstDefined(
      item.lead_context?.cep,
      item.lead?.cep,
      item.cep
    )
  )
};

// =========================
// CONVERSATION LIMPA
// =========================
const conversation = {
  last_message: normalizeText(
    firstDefined(
      item.conversation?.last_message,
      item.last_message,
      item.mensagem,
      item.message
    )
  ) || "",

  history: normalizeText(
    firstDefined(
      item.conversation?.history,
      item.history,
      item.historico
    )
  )
};

// =========================
// DETECTED FIELDS INICIAIS
// Mantém somente o que ajuda o SDR.
// Sem carregar estrutura de classifier.
// =========================
const detectedFields = {
  nome: normalizeText(
    firstDefined(
      item.detected_fields?.nome,
      item.detected_fields?.name
    )
  ),

  produto: normalizeText(
    firstDefined(
      item.detected_fields?.produto,
      item.detected_fields?.produto_mencionado,
      item.detected_fields?.product,
      leadContext.product_interest
    )
  ),

  cidade: normalizeText(
    firstDefined(
      item.detected_fields?.cidade,
      leadContext.city
    )
  ),

  cep: normalizeCep(
    firstDefined(
      item.detected_fields?.cep,
      leadContext.cep
    )
  ),

  endereco: normalizeText(
    firstDefined(
      item.detected_fields?.endereco,
      item.detected_fields?.address
    )
  )
};

// =========================
// CONTEXTO KB
// =========================
const contextoKb = normalizeText(item.contexto_kb) || "";

// =========================
// OUTPUT SANITIZADO PARA SDR
// IMPORTANTE:
// - NÃO passa classification
// - NÃO passa crm_context
// - NÃO passa stage_decision
// - NÃO passa route_hint
// - NÃO passa score/tags
// =========================
return [
  {
    json: {
      contexto_kb: contextoKb,
      lead_context: leadContext,
      conversation: conversation,
      detected_fields: detectedFields
    }
  }
];
